    def _on_template_changed(self, file_paths: t.List[str]) -> None:
        """Invalidate cached templates that correspond to the given
        changed file paths. Intended for use by search path monitors
        (and directly by tests) to notify the loader that template
        source files were created, modified, or deleted.

        :param file_paths: Absolute paths of the files that changed.
        """
        names = set()

        for file_path in file_paths:
            file_path = os.path.abspath(file_path)

            for searchpath in self.searchpath:
                searchpath = os.path.abspath(searchpath)

                try:
                    common = os.path.commonpath([searchpath, file_path])
                except ValueError:
                    continue

                if common != searchpath:
                    continue

                name = os.path.relpath(file_path, searchpath).replace(
                    os.path.sep, "/"
                )
                names.add(name)
                break

        if not names:
            return

        for environment in self._environments:
            if environment.cache is None:
                continue

            for name in names:
                environment.cache.pop((weakref.ref(self), name), None)


